#include<bits/stdc++.h>
using namespace std;
long long n,ans;
int pos[40],c[40],p[40],q[40];
void dfs(int x){
    if(x>n){
        ans++;
        if(ans<=3){
            for(int i=1;i<=n;i++){
                cout<<pos[i]<<" ";
            }
            cout<<endl;
        }
        return ;
    }
    for(int i=1;i<=n;i++){
        if(c[i]||p[x+i]||q[x-i+n]) continue;
        pos[x]=i;
        c[i]=p[x+i]=q[x-i+n]=1;
        dfs(x+1);
        c[i]=p[x+i]=q[x-i+n]=0;
    }
}
int main(){
    cin>>n;
    dfs(1);
    cout<<ans;
    return 0;
}
